def main():
    data = json.loads(DATA_PATH.read_text(encoding="utf-8-sig"))
    analysis = next(item for item in data["analysis"] if int(item["year"]) == 110)
    for question in analysis["questions"]:
        no = int(question["no"])
        if no in SOLUTIONS:
            question["solution"] = SOLUTIONS[no]
            question["commonMistakes"] = "常見錯誤：沒有先列出物理模型與守恆關係；計算時漏掉單位換算、力臂、方向或有效的相對運動條件。"
            question["keyConcept"] = "關鍵觀念：以因次分析、功-能定理、拋體運動、週期公式、力矩平衡、彈性碰撞與駐波共鳴條件逐步推導。"
    DATA_PATH.write_text(
        "\ufeff" + json.dumps(data, ensure_ascii=False, indent=2),
        encoding="utf-8",
    )


if __name__ == "__main__":
    main()
